(self.webpackChunk=self.webpackChunk||[]).push([[488],{4357:(t,e,n)=>{"use strict";n.r(e),n.d(e,{data:()=>s});const s={key:"v-9c812d4e",path:"/linux/linux.html",title:"linux基本命令操作",lang:"en-US",frontmatter:{title:"linux基本命令操作"},excerpt:"",headers:[{level:2,title:"命令替换",slug:"命令替换",children:[]},{level:2,title:"${ }变量替换",slug:"变量替换",children:[{level:3,title:"取路径、文件名、后缀",slug:"取路径、文件名、后缀",children:[]},{level:3,title:"取子串及替换",slug:"取子串及替换",children:[]},{level:3,title:"根据状态为变量赋值",slug:"根据状态为变量赋值",children:[]},{level:3,title:"数组",slug:"数组",children:[]},{level:3,title:"$(( ))与整数运算",slug:"与整数运算",children:[]},{level:3,title:"进制转换",slug:"进制转换",children:[]},{level:3,title:"(())重定义变量值",slug:"重定义变量值",children:[]}]},{level:2,title:"shell脚本中自动获取 GitHub 最新版本号",slug:"shell脚本中自动获取-github-最新版本号",children:[{level:3,title:"代码解释",slug:"代码解释",children:[]}]}],filePathRelative:"linux/linux.md",git:{updatedTime:1626154667e3,contributors:[]}}},9832:(t,e,n)=>{"use strict";n.r(e),n.d(e,{default:()=>a});const s=(0,n(6252).uE)('<h2 id="命令替换" tabindex="-1"><a class="header-anchor" href="#命令替换" aria-hidden="true">#</a> 命令替换</h2><ul><li><p>在bash中，<code>$()</code>与<code>` `</code> （反引号）都是用来作命令替换的。</p><p><span style="color:red;"><code>$()</code>比较直观，但是<code>$()</code>不一定所有的linux系统都支持。</span></p></li></ul><h2 id="变量替换" tabindex="-1"><a class="header-anchor" href="#变量替换" aria-hidden="true">#</a> ${ }变量替换</h2><ul><li>一般情况下，$var与${var}是没有区别的，但是用${ }会比较精确的界定变量名称的范围</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>先赋值一个变量为一个路径，如下：\n<span class="token assign-left variable">file</span><span class="token operator">=</span>/dir1/dir2/dir3/my.file.txt\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="取路径、文件名、后缀" tabindex="-1"><a class="header-anchor" href="#取路径、文件名、后缀" aria-hidden="true">#</a> <strong>取路径、文件名、后缀</strong></h3><table><thead><tr><th style="text-align:center;">命令</th><th style="text-align:center;">解释</th><th style="text-align:center;">结果</th></tr></thead><tbody><tr><td style="text-align:center;">${file#*/}</td><td style="text-align:center;">拿掉第一条 / 及其左边的字符串</td><td style="text-align:center;">dir1/dir2/dir3/my.file.txt</td></tr><tr><td style="text-align:center;">${file##*/}</td><td style="text-align:center;">拿掉最后一条 / 及其左边的字符串</td><td style="text-align:center;">my.file.txt</td></tr><tr><td style="text-align:center;">${file#*.}</td><td style="text-align:center;">拿掉第一个 . 及其左边的字符串</td><td style="text-align:center;">file.txt</td></tr><tr><td style="text-align:center;">${file##*.}</td><td style="text-align:center;">拿掉最后一个 . 及其左边的字符串</td><td style="text-align:center;">txt</td></tr><tr><td style="text-align:center;">${file%/*}</td><td style="text-align:center;">拿掉最后一条 / 及其右边的字符串</td><td style="text-align:center;">/dir1/dir2/dir3</td></tr><tr><td style="text-align:center;">${file%%/*}</td><td style="text-align:center;">拿掉第一条 / 及其右边的字符串</td><td style="text-align:center;">(空值)</td></tr><tr><td style="text-align:center;">${file%.*}</td><td style="text-align:center;">拿掉最后一个 . 及其右边的字符串</td><td style="text-align:center;">/dir1/dir2/dir3/my.file</td></tr><tr><td style="text-align:center;">${file%%.*}</td><td style="text-align:center;">拿掉第一个 . 及其右边的字符串</td><td style="text-align:center;">/dir1/dir2/dir3/my￼</td></tr></tbody></table><hr><p><span style="color:red;"><strong>记忆方法</strong></span></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code># 是去掉左边(在键盘上 # 在 $ 之左边)\n% 是去掉右边(在键盘上 % 在 $ 之右边)\n单一符号是最小匹配;两个符号是最大匹配\n*是用来匹配不要的字符，也就是想要去掉的那部分\n还有指定字符分隔号，与*配合，决定取哪部分\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="取子串及替换" tabindex="-1"><a class="header-anchor" href="#取子串及替换" aria-hidden="true">#</a> <strong>取子串及替换</strong></h3><table><thead><tr><th style="text-align:center;">命令</th><th style="text-align:center;">解释</th><th style="text-align:center;">结果</th></tr></thead><tbody><tr><td style="text-align:center;">${file:0:5}</td><td style="text-align:center;">提取最左边的 5 个字节</td><td style="text-align:center;">/dir1</td></tr><tr><td style="text-align:center;">${file:5:5}</td><td style="text-align:center;">提取第 5 个字节右边的连续 5 个字节</td><td style="text-align:center;">/dir2</td></tr><tr><td style="text-align:center;">${file/dir/path}</td><td style="text-align:center;">将第一个 dir 提换为 path</td><td style="text-align:center;">/path1/dir2/dir3/my.file.txt</td></tr><tr><td style="text-align:center;">${file//dir/path}</td><td style="text-align:center;">将全部 dir 提换为 path</td><td style="text-align:center;">/path1/path2/path3/my.file.txt</td></tr><tr><td style="text-align:center;">${#file}</td><td style="text-align:center;">获取变量长度</td><td style="text-align:center;">27</td></tr></tbody></table><h3 id="根据状态为变量赋值" tabindex="-1"><a class="header-anchor" href="#根据状态为变量赋值" aria-hidden="true">#</a> <strong>根据状态为变量赋值</strong></h3><table><thead><tr><th style="text-align:center;"><strong>命令</strong></th><th style="text-align:center;"><strong>解释</strong></th><th style="text-align:center;"><strong>备注</strong></th></tr></thead><tbody><tr><td style="text-align:center;">${file-my.file.txt}</td><td style="text-align:center;">若 $file 没设定,则使用 my.file.txt 作传回值</td><td style="text-align:center;">空值及非空值不作处理</td></tr><tr><td style="text-align:center;">${file:-my.file.txt}</td><td style="text-align:center;">若 $file 没有设定或为空值,则使用 my.file.txt 作传回值</td><td style="text-align:center;">非空值时不作处理</td></tr><tr><td style="text-align:center;">${file+my.file.txt}</td><td style="text-align:center;">若$file 设为空值或非空值,均使用my.file.txt作传回值</td><td style="text-align:center;">没设定时不作处理</td></tr><tr><td style="text-align:center;">${file:+my.file.txt}</td><td style="text-align:center;">若 $file 为非空值,则使用 my.file.txt 作传回值</td><td style="text-align:center;">没设定及空值不作处理</td></tr><tr><td style="text-align:center;">${file=txt}</td><td style="text-align:center;">若 $file 没设定,则回传 txt ,并将 $file 赋值为 txt</td><td style="text-align:center;">空值及非空值不作处理</td></tr><tr><td style="text-align:center;">${file:=txt}</td><td style="text-align:center;">若 $file 没设定或空值,则回传 txt ,将 $file 赋值为txt</td><td style="text-align:center;">非空值时不作处理</td></tr><tr><td style="text-align:center;">${file?my.file.txt}</td><td style="text-align:center;">若 $file 没设定,则将 my.file.txt 输出至 STDERR</td><td style="text-align:center;">空值及非空值不作处理</td></tr><tr><td style="text-align:center;">${file:?my.file.txt}</td><td style="text-align:center;">若 $file没设定或空值,则将my.file.txt输出至STDERR</td><td style="text-align:center;">非空值时不作处理</td></tr></tbody></table><h3 id="数组" tabindex="-1"><a class="header-anchor" href="#数组" aria-hidden="true">#</a> 数组</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token assign-left variable">A</span><span class="token operator">=</span><span class="token string">&quot;a b c def&quot;</span>   <span class="token comment"># 定义字符串</span>\n<span class="token assign-left variable">A</span><span class="token operator">=</span><span class="token punctuation">(</span>a b c def<span class="token punctuation">)</span>   <span class="token comment"># 定义字符数组</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><table><thead><tr><th style="text-align:center;"><strong>命令</strong></th><th style="text-align:center;"><strong>解释</strong></th><th style="text-align:center;"><strong>结果</strong></th></tr></thead><tbody><tr><td style="text-align:center;">${A[@]}</td><td style="text-align:center;">返回数组全部元素</td><td style="text-align:center;">a b c def</td></tr><tr><td style="text-align:center;">${A[*]}</td><td style="text-align:center;">同上</td><td style="text-align:center;">a b c def</td></tr><tr><td style="text-align:center;">${A[0]}</td><td style="text-align:center;">返回数组第一个元素</td><td style="text-align:center;">a</td></tr><tr><td style="text-align:center;">${#A[@]}</td><td style="text-align:center;">返回数组元素总个数</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:center;">${#A[*]}</td><td style="text-align:center;">同上</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:center;">${#A[3]}</td><td style="text-align:center;">返回第四个元素的长度，即def的长度</td><td style="text-align:center;">3</td></tr><tr><td style="text-align:center;">A[3]=xzy</td><td style="text-align:center;">则是将第四个组数重新定义为 xyz</td><td style="text-align:center;"></td></tr></tbody></table><h3 id="与整数运算" tabindex="-1"><a class="header-anchor" href="#与整数运算" aria-hidden="true">#</a> $(( ))与整数运算</h3><table><thead><tr><th style="text-align:center;">符号</th><th style="text-align:center;"><strong>功能</strong></th></tr></thead><tbody><tr><td style="text-align:center;">+ - * /</td><td style="text-align:center;">分别为加、减、乘、除</td></tr><tr><td style="text-align:center;">%</td><td style="text-align:center;">余数运算</td></tr><tr><td style="text-align:center;">&amp; |^ !</td><td style="text-align:center;">分别为“AND、OR、XOR、NOT”</td></tr></tbody></table><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>在 <span class="token variable"><span class="token variable">$((</span> <span class="token variable">))</span></span> 中的变量名称,可于其前面加 $ 符号来替换,也可以不用。\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $((2*3))</span>\n<span class="token number">6</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># a=5;b=7;c=2</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $((a+b*c))</span>\n<span class="token number">19</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $(($a+$b*$c))</span>\n<span class="token number">19</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="进制转换" tabindex="-1"><a class="header-anchor" href="#进制转换" aria-hidden="true">#</a> <strong>进制转换</strong></h3><p><strong>$(( ))可以将其他进制转成十进制数显示出来。用法如下： <code>echo $((N#xx))</code> 其中，N为进制，xx为该进制下某个数值，命令执行后可以得到该进制数转成十进制后的值。</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $((2#110))</span>\n<span class="token number">6</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $((16#2a))</span>\n<span class="token number">42</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $((8#11))</span>\n<span class="token number">9</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="重定义变量值" tabindex="-1"><a class="header-anchor" href="#重定义变量值" aria-hidden="true">#</a> (())重定义变量值</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># a=5;b=7</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># ((a++))</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo $a</span>\n<span class="token number">6</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># ((a--));echo $a</span>\n<span class="token number">5</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># ((a&lt;b));echo $?</span>\n<span class="token number">0</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># ((a&gt;b));echo $?</span>\n<span class="token number">1</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="shell脚本中自动获取-github-最新版本号" tabindex="-1"><a class="header-anchor" href="#shell脚本中自动获取-github-最新版本号" aria-hidden="true">#</a> shell脚本中自动获取 GitHub 最新版本号</h2><p>利用 <code>GitHub API</code> 获取最新 <code>Releases</code> 的版本号，以 <code>iina</code> 为例：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">wget</span> -qO- -t1 -T2 <span class="token string">&quot;https://api.github.com/repos/lhc70000/iina/releases/latest&quot;</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token string">&quot;tag_name&quot;</span> <span class="token operator">|</span> <span class="token function">head</span> -n <span class="token number">1</span> <span class="token operator">|</span> <span class="token function">awk</span> -F <span class="token string">&quot;:&quot;</span> <span class="token string">&#39;{print $2}&#39;</span> <span class="token operator">|</span> <span class="token function">sed</span> <span class="token string">&#39;s/\\&quot;//g;s/,//g;s/ //g&#39;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>或者借助第三方工具 <code>jq</code> ：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>wget -qO- -t1 -T2 &quot;https://api.github.com/repos/lhc70000/iina/releases/latest&quot; | jq -r &#39;.tag_name&#39;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="代码解释" tabindex="-1"><a class="header-anchor" href="#代码解释" aria-hidden="true">#</a> 代码解释</h3><h4 id="主字段" tabindex="-1"><a class="header-anchor" href="#主字段" aria-hidden="true">#</a> 主字段</h4><p><code>https://api.github.com/repos/lhc70000/iina/releases/latest</code> 这里用的是 GitHub 的官方 API，格式为 <code>https://api.github.com/repos/{项目名}/releases/latest</code> 打开上述链接后，可见包含下述字段的内容：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&quot;html_url&quot;: &quot;https://github.com/lhc70000/iina/releases/tag/v0.0.15.1&quot;,\n&quot;id&quot;: 10774475,\n&quot;node_id&quot;: &quot;MDc6UmVsZWFzZTEwNzc0NDc1&quot;,\n&quot;tag_name&quot;: &quot;v0.0.15.1&quot;,\n&quot;target_commitish&quot;: &quot;0.0.15.1&quot;,\n&quot;name&quot;: &quot;v0.0.15.1&quot;,\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>那么这里的 <code>tag_name</code> 后面的值就是我们所需要的东西。</p><h4 id="wget参数" tabindex="-1"><a class="header-anchor" href="#wget参数" aria-hidden="true">#</a> wget参数</h4><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>wget -qO- -t1 -T2` ，在这里我们使用了 4 个参数，分别是 `q` , `O-` , `t1` , `T2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><ul><li><code>-q</code> : <code>q</code> 就是 <code>quiet</code> 的意思了，没有该参数将会显示从请求到输出全过程的所有内容，这肯定不是我们想要的。</li><li><code>-O-</code>: <code>-O</code> 是指把文档写入文件中，而 <code>-O-</code> 是将内容写入标准输出，而不保存为文件。（注：这里是大写英文字母 <code>O</code> (Out)，不是数字 <code>0</code> ）</li><li><code>-t1</code> : 设定最大尝试链接次数为 <code>1</code> 次，防止失败后反复获取，导致后续脚本无法执行。</li><li><code>-T2</code> : 设定响应超时的秒数为 <code>2</code> 秒，防止失败后反复获取，导致后续脚本无法执行。</li></ul><h4 id="筛选参数" tabindex="-1"><a class="header-anchor" href="#筛选参数" aria-hidden="true">#</a> 筛选参数</h4><ul><li><code>jq -r &#39;.tag_name&#39;</code> ：该命令需要先安装 <code>jq</code> ，<code>.tag_name</code> 取得该键值，<code>-r</code> 参数删除键值中的 <code>&quot;</code></li><li><code>grep &quot;tag_name&quot;</code> : <code>grep</code> 是 Linux 一个强大的文本搜索工具，在本代码中输出 <code>tag_name</code> 所在行，即输出 <code>&quot;tag_name&quot;: &quot;v0.0.15.1&quot;,</code></li><li><code>head -n 1</code> : <code>head -n</code> 用于显示输出的行数，考虑到某些项目可能存在多个不同版本的 <code>tag_name</code> ，这里我们只要第一个。</li><li><code>awk -F &quot;:&quot; &#39;{print $2}&#39;</code> : <code>awk</code> 主要用于文本分析，在这里指定 <code>:</code> 为分隔符，将该行切分成多列，并输出第二列。于是我们得到了 <code>(空格)&quot;v0.0.15.1&quot;,</code></li><li><code>sed &#39;s/\\&quot;//g;s/,//g;s/ //g&#39;</code> : 在这里 <code>sed</code> 用于数据查找替换，如 <code>sed &#39;s/要被取代的字串/新的字串/g&#39;</code> ，因此本段命令可分为 3 个，以 <code>;</code> 分隔。<code>s/\\&quot;//g</code> 即将 <code>&quot;</code> 删除（反斜杠是为了防止引号被转义），以此类推，最终留下我们需要的内容：<code>v0.0.15.1</code> 。</li></ul>',40),a={render:function(t,e){return s}}}}]);